{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMPOqIYFtCvKrdGhLQ1j09G"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"GiT5cAlX1tYz"},"outputs":[],"source":["import streamlit as st\n","import joblib\n","import pandas as pd\n","\n","# Judul Aplikasi di HP\n","st.set_page_config(page_title=\"Seakeeping Monitor\", page_icon=\"🚢\")\n","st.title(\"🚢 Monitor Kapal Iqbal\")\n","\n","# Input dengan Slider agar mudah digeser di HP\n","st.sidebar.header(\"Input Data Sensor\")\n","w = st.sidebar.slider(\"Tinggi Gelombang (m)\", 0.0, 5.0, 1.5)\n","s = st.sidebar.slider(\"Kecepatan (Knot)\", 0, 20, 10)\n","h = st.sidebar.slider(\"Heading (Derajat)\", 0, 180, 90)\n","\n","# Load Model\n","model = joblib.load('model_seakeeping_kapal.sav')\n","\n","# Proses Prediksi\n","df_in = pd.DataFrame([[w, s, h]], columns=['Wave_m', 'Speed_Knot', 'Heading_deg'])\n","res = model.predict(df_in)\n","h_val, p_val, r_val = res[0][0], res[0][1], res[0][2]\n","\n","# Tampilan Hasil (Indikator Besar)\n","st.write(f\"### Kondisi Laut Saat Ini: {w}m\")\n","col1, col2, col3 = st.columns(3)\n","col1.metric(\"Heave\", f\"{h_val:.2f} m\")\n","col2.metric(\"Pitch\", f\"{p_val:.2f} °\")\n","col3.metric(\"Roll\", f\"{r_val:.2f} °\")\n","\n","# Logika Early Warning\n","if r_val > 3.0:\n","    st.error(\"🚨 PERINGATAN: Kapal tidak aman! Kurangi kecepatan atau ubah heading.\")\n","else:\n","    st.success(\"✅ Kapal beroperasi dalam batas aman.\")\n","\n","# Hitung Indeks Operabilitas\n","skor = (int(h_val <= 1.0) + int(p_val <= 1.5) + int(r_val <= 3.0)) / 3 * 100\n","st.info(f\"**Indeks Operabilitas: {skor:.1f}%**\")\n"]}]}